def _add_translation_variants(translations):
    expanded = dict(translations)
    trailing_marks = '.:،؟!؛'
    for source_text, target_translations in list(translations.items()):
        normalized = source_text.strip()
        trimmed = normalized.rstrip(trailing_marks).strip()
        if trimmed and trimmed != normalized and trimmed not in expanded:
            expanded[trimmed] = target_translations
    return expanded


UI_TRANSLATIONS = _add_translation_variants(UI_TRANSLATIONS)


def get_active_ui_language():
    language = (get_language() or 'ar').lower()
    if language.startswith('zh'):
        return 'zh-hans'
    return language


def translate_ui_text(text, language=None):
    source_text = str(text or '')
    lang = (language or get_active_ui_language() or 'ar').lower()
    if lang == 'ar':
        return source_text
    translations = UI_TRANSLATIONS.get(source_text)
    if not translations:
        return source_text
    return translations.get(lang) or source_text
